import{_ as a,o as t,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Facebook SKAdNetwork","description":"","frontmatter":{"title":"Facebook SKAdNetwork","slug":"facebook-skadnetwork"},"headers":[],"relativePath":"marketer-hub/facebook-skadnetwork.md","filePath":"marketer-hub/facebook-skadnetwork.md"}'),r={name:"marketer-hub/facebook-skadnetwork.md"};function i(s,e,d,h,c,l){return t(),o("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The introduction of iOS 14.5 came with the rise of SKAdNetwork (SKAN) that had industry-wide impacts on the mobile measurement and attribution ecosystem. As such, Facebook will work differently from most non-self-attribution networks when it comes to SKAdNetwork campaigns.</p><p>Facebook will not be forwarding individual SKAdNetwork Postbacks to Branch. However, aggregate SKAN data will be passed back via Facebook’s Ads Insights API. In this flow, Facebook collects individual SKAN postbacks, cryptographically validates them internally, and then provides only pre-generated results to Branch via an API endpoint. Additionally, data shared via API is may not include all data dimensions reflected in the SKAdNetwork postbacks.</p><h2 id="facebook-skan-support" tabindex="-1">Facebook SKAN Support <a class="header-anchor" href="#facebook-skan-support" aria-label="Permalink to &quot;Facebook SKAN Support&quot;">​</a></h2><h3 id="supported-campaigns" tabindex="-1">Supported Campaigns <a class="header-anchor" href="#supported-campaigns" aria-label="Permalink to &quot;Supported Campaigns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Facebook Campaign Type</th><th>SKAdNetwork Support for Branch</th></tr></thead><tbody><tr><td>Mobile App Install (MAI)</td><td>✅ Provides aggregate SKAN data to Branch via API</td></tr><tr><td>App Event Optimization (AEO)</td><td>✅ Provides aggregate SKAN data to Branch via API</td></tr><tr><td>Value Optimization (VO)</td><td>✅ Provides aggregate SKAN data to Branch via API</td></tr><tr><td><em><strong>All others</strong></em></td><td>❌ Does not support SKAN</td></tr></tbody></table><h3 id="supported-data-dimensions-via-api" tabindex="-1">Supported Data Dimensions via API <a class="header-anchor" href="#supported-data-dimensions-via-api" aria-label="Permalink to &quot;Supported Data Dimensions via API&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Data Support</th></tr></thead><tbody><tr><td>Download/Install</td><td>✅</td></tr><tr><td>Reinstall</td><td>❌</td></tr><tr><td>Conversion Value</td><td>✅</td></tr><tr><td>Campaign Name</td><td>✅</td></tr><tr><td>Campaign ID</td><td>✅</td></tr></tbody></table><h4 id="data-not-shared-by-facebook" tabindex="-1">Data Not Shared by Facebook <a class="header-anchor" href="#data-not-shared-by-facebook" aria-label="Permalink to &quot;Data Not Shared by Facebook&quot;">​</a></h4><ul><li><p>Install vs. Reinstall</p><ul><li>Facebook does not share this via the API; therefore, all data is considered download/install in Branch systems.</li></ul></li></ul><h2 id="implementation-via-api" tabindex="-1">Implementation via API <a class="header-anchor" href="#implementation-via-api" aria-label="Permalink to &quot;Implementation via API&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Authentication</p><p>You must have authenticated Facebook within Branch for Branch to receive and report on SKAN data. Follow our guide <a href="./facebook-app-install-ads.html">here</a>.</p></div><div class="danger custom-block"><p class="custom-block-title">Important notes about which customers should use this endpoint</p><p>The Conversion Bit Schema sync functionality is intended to support customers who are using the Branch SDK for SKAdNetwork support.</p><p>If you are:</p><ul><li><p><strong>Using the Facebook SDK for SKAdNetwork.</strong> You should not use this endpoint. Facebook will automatically pull in their own <code>conversion-value</code> schema.</p></li><li><p><strong>Calling SKAN methods natively in your app</strong>. You <em>may</em> be able to use this endpoint:</p><ul><li>Option 1: Facebook provides functionality within the Facebook Events Manager to specify your conversion value mapping. See <a href="https://www.facebook.com/business/help/670955636925518" target="_blank" rel="noreferrer">this Facebook guide</a> for more info. <strong>This is the recommended option if you are calling SKAN methods natively,</strong> and in this case, you should not use the endpoint.</li><li>Option 2: If your custom conversion value mapping exactly matches Branch SDK functionality (1 in-app event is mapped directly to 1 SKAN <code>conversion-value</code> value) <em>and</em> you have properly entered this by using custom SKAN event labels in Branch&#39;s dashboard mapping tool, you can use the endpoint above. However, the endpoint will <strong>not</strong> work as expected if you are using a more complex custom conversion value strategy, such as revenue buckets or event counts.</li></ul></li></ul></div><p>To sync SKAdNetwork conversion value mappings with Facebook for campaign optimization, Branch provides an API endpoint that customers may paste into the Facebook Ads Manager UI.</p><p>The API endpoint follows this format, and can only be called by Facebook&#39;s services:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api2.branch.io/v3/partners/a_facebook/conversion-value-mappings?app_id={itunes_id}</span></span></code></pre></div><p><strong>Note:</strong> the <code>{itunes_id}</code> parameter must be replaced with the respective iTunes ID for your app (<strong>not</strong> your Branch app ID). Your iTunes ID is the series of numbers at the end of your app&#39;s App Store page URL.</p><p>For example: <code>https://apps.apple.com/us/app/branch-monster-factory/id917737838</code> would have an endpoint URL of <code>https://api2.branch.io/v3/partners/a_facebook/conversion-value-mappings?app_id=917737838</code></p><h4 id="_1-navigate-to-facebook-in-the-branch-dashboard-s-ads-partner-management" tabindex="-1">1. Navigate to Facebook in the Branch Dashboard&#39;s Ads Partner Management <a class="header-anchor" href="#_1-navigate-to-facebook-in-the-branch-dashboard-s-ads-partner-management" aria-label="Permalink to &quot;1. Navigate to Facebook in the Branch Dashboard&#39;s Ads Partner Management&quot;">​</a></h4><p>a. Log in to your <a href="https://dashboard.branch.io" target="_blank" rel="noreferrer">Branch Dashboard</a><br> b. On the left-hand navigation bar navigate to Ads → Partner Management<br> c. Search or scroll to find Facebook</p><p><strong>Note:</strong> Conversion Value URL will only be visible for customers that have <a href="https://dashboard.branch.io/ads/skadnetwork/configuration/sdk-opt-in" target="_blank" rel="noreferrer">opted into Branch SDK support on the SKAdNetwork Configurations</a>.</p><h4 id="_2-copy-the-url" tabindex="-1">2. Copy the URL <a class="header-anchor" href="#_2-copy-the-url" aria-label="Permalink to &quot;2. Copy the URL&quot;">​</a></h4><p><strong>Note</strong>: When copied to your clipboard using the blue button, the <code>{itunes_id}</code> parameter will automatically be filled in with the correct iTunes ID.</p><h4 id="_3-go-to-facebook-ads-manager-and-navigate-to-events-manager" tabindex="-1">3. Go to Facebook Ads Manager and navigate to Events Manager <a class="header-anchor" href="#_3-go-to-facebook-ads-manager-and-navigate-to-events-manager" aria-label="Permalink to &quot;3. Go to Facebook Ads Manager and navigate to Events Manager&quot;">​</a></h4><p><em>[Image: 3208]</em></p><h4 id="_4-go-to-settings-highlighted-in-the-screenshot-above-and-select-set-up-events-under-configure-app-events-for-skadnetwork" tabindex="-1">4. Go to &quot;Settings&quot; highlighted in the screenshot above and select &quot;Set Up Events&quot; under Configure App Events for SKAdNetwork <a class="header-anchor" href="#_4-go-to-settings-highlighted-in-the-screenshot-above-and-select-set-up-events-under-configure-app-events-for-skadnetwork" aria-label="Permalink to &quot;4. Go to &quot;Settings&quot; highlighted in the screenshot above and select &quot;Set Up Events&quot; under Configure App Events for SKAdNetwork&quot;">​</a></h4><p><em>[Image: 890]</em></p><h4 id="_5-select-import-from-partner-app" tabindex="-1">5. Select &quot;Import from Partner App&quot; <a class="header-anchor" href="#_5-select-import-from-partner-app" aria-label="Permalink to &quot;5. Select &quot;Import from Partner App&quot;&quot;">​</a></h4><h4 id="_6-paste-the-url-copied-from-step-2-and-click-connect" tabindex="-1">6. Paste the URL copied from step 2 and click &quot;Connect&quot; <a class="header-anchor" href="#_6-paste-the-url-copied-from-step-2-and-click-connect" aria-label="Permalink to &quot;6. Paste the URL copied from step 2 and click &quot;Connect&quot;&quot;">​</a></h4><p><em>[Image: 2110]</em></p><h2 id="skan-reports" tabindex="-1">SKAN Reports <a class="header-anchor" href="#skan-reports" aria-label="Permalink to &quot;SKAN Reports&quot;">​</a></h2><p>You can use the Branch Dashboard to view reporting on all of your SKAN-related campaigns. If you want to look at just Facebook SKAN data, you can apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>ad network</td><td>equals</td><td><code>a_facebook</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Additional Resources</p><p>You can see more ways to view SKAN Reports with our guide <a href="./skadnetwork-dashboard-reports.html">here</a>.</p></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h4 id="connection-error-when-entering-our-branch-conversion-schema-url" tabindex="-1">Connection error when entering our Branch conversion schema URL <a class="header-anchor" href="#connection-error-when-entering-our-branch-conversion-schema-url" aria-label="Permalink to &quot;Connection error when entering our Branch conversion schema URL&quot;">​</a></h4><p>If you receive the following error when pasting the Branch conversion schema URL:</p><p><em>[Image: 1216]</em></p><p>Please ensure the following:</p><ul><li>You must have your app enabled for SKAdNetwork via the Branch dashboard (see <a href="./enable-skadnetwork.html">this page</a> for more).</li><li>You must have at least one conversion value mapped using the Branch dashboard (otherwise Facebook will just get an empty response from Branch&#39;s API).</li></ul><h4 id="branch-dashboard-data-sync" tabindex="-1">Branch Dashboard Data Sync <a class="header-anchor" href="#branch-dashboard-data-sync" aria-label="Permalink to &quot;Branch Dashboard Data Sync&quot;">​</a></h4><p>If you feel the data that you see in the Branch Dashboard is not correct, we recommend waiting 24-48 hours after implementation. Data on the Branch Dashboard is reflected by the Facebook conversion date and <strong>not</strong> the Branch ingestion date. It has a similar delay to cost data displayed on traditional SAN app install campaigns.</p>',42)])])}const b=a(r,[["render",i]]);export{u as __pageData,b as default};
